In this binary search implementation, which line number has the bug?
int bs(vector<int>&v,int target){
  int l=0,r=v.size()-1;    //line 1
  while(l<r){               //line 2
    int mid=(l+r)/2;        //line 3
    if(v[mid]==target) return mid; //line 4
    else if(v[mid]<target) l=mid;  //line 5
    else r=mid-1;           //line 6
  }
  return -1;
}

